        const skipHeader = subdivisionImportSkipHeader ? Boolean(subdivisionImportSkipHeader.checked) : true;
        const parsed = parseImportValues(rows, skipHeader, ['nome', 'subdivisao', 'subdivisão']);
        const uniq = new Set(parsed);
