function openOCCReportPrintWindow({ reportName, bodyHtml, extraStyles = '', width = 1024, height = 760 } = {}) {
    const w = window.open('', '_blank', `width=${Number(width) || 1024},height=${Number(height) || 760}`);
    if (!w) {
        showToast('Habilite pop-ups para imprimir.', true);
        return false;
    }
    w.document.write(buildOccReportHtml({ reportName, bodyHtml, extraStyles }));
    w.document.close();
    w.focus();
    setTimeout(() => w.print(), 350);
    return true;
}

function extractLegacyReportParts(legacyHtml) {
    try {
        const doc = new DOMParser().parseFromString(String(legacyHtml || ''), 'text/html');
        doc.querySelectorAll('script').forEach(el => el.remove());
        doc.querySelectorAll('.footer').forEach(el => {
            const t = String(el && el.textContent || '').toLowerCase();
            const hasDocumento = t.includes('documento');
            const hasTotal = t.includes('total') || t.includes('quantidade') || t.includes('subtotal');
            if (hasDocumento && !hasTotal) el.remove();
        });
        const styles = Array.from(doc.querySelectorAll('style')).map(s => String(s.textContent || '')).join('\n');
        const body = doc.body ? String(doc.body.innerHTML || '') : String(legacyHtml || '');
        return { bodyHtml: body, extraStyles: styles };
    } catch {
        return { bodyHtml: String(legacyHtml || ''), extraStyles: '' };
    }
}

function openOCCReportPrintWindowFromLegacyHtml({ reportName, legacyHtml, width = 1024, height = 760 } = {}) {
    const parts = extractLegacyReportParts(legacyHtml);
    return openOCCReportPrintWindow({ reportName, bodyHtml: parts.bodyHtml, extraStyles: parts.extraStyles, width, height });
}

function openStockReportPrintWindow(title, html) {
    return openOCCReportPrintWindow({ reportName: title, bodyHtml: html, width: 1024, height: 760 });
}

function parseDateFromInput(value, endOfDay = false) {
    const v = String(value || '').trim();
    if (!v) return null;
    let y = 0; let m = 0; let d = 0;
    if (v.includes('-')) {
        const parts = v.split('-').map(Number);
        if (parts.length === 3) {
            y = parts[0]; m = parts[1]; d = parts[2];
        }
    } else if (v.includes('/')) {
        const parts = v.split('/').map(Number);
        if (parts.length === 3) {
            d = parts[0]; m = parts[1]; y = parts[2];
        }
    }
    if (!y || !m || !d) return null;
    if (endOfDay) return new Date(y, m - 1, d, 23, 59, 59, 999);
    return new Date(y, m - 1, d, 0, 0, 0, 0);
}

function formatDateInput(date) {
    const d = date instanceof Date ? date : new Date(date);
    if (!Number.isFinite(d.getTime())) return '';
    const y = d.getFullYear();
    const m = String(d.getMonth() + 1).padStart(2, '0');
    const day = String(d.getDate()).padStart(2, '0');
    return `${y}-${m}-${day}`;
}

function applyInventoryReportDatePreset(preset) {
    const startInput = document.getElementById('inventoryReportStartDate');
    const endInput = document.getElementById('inventoryReportEndDate');
    if (!startInput || !endInput) return;
    const now = new Date();
    if (preset === 'today') {
        startInput.value = formatDateInput(now);
        endInput.value = formatDateInput(now);
    } else if (preset === 'last_7_days') {
        const start = new Date(now);
        start.setDate(start.getDate() - 6);
        startInput.value = formatDateInput(start);
        endInput.value = formatDateInput(now);
    } else if (preset === 'current_month') {
        const firstCurrentMonth = new Date(now.getFullYear(), now.getMonth(), 1);
        startInput.value = formatDateInput(firstCurrentMonth);
        endInput.value = formatDateInput(now);
    } else if (preset === 'week') {
        const start = new Date(now);
        const day = start.getDay();
        const diff = day === 0 ? 6 : day - 1;
        start.setDate(start.getDate() - diff);
        startInput.value = formatDateInput(start);
        endInput.value = formatDateInput(now);
    } else if (preset === 'last_month') {
        const firstCurrentMonth = new Date(now.getFullYear(), now.getMonth(), 1);
        const firstLastMonth = new Date(firstCurrentMonth.getFullYear(), firstCurrentMonth.getMonth() - 1, 1);
        const lastLastMonth = new Date(firstCurrentMonth.getTime() - 1);
        startInput.value = formatDateInput(firstLastMonth);
        endInput.value = formatDateInput(lastLastMonth);
    }
    inventoryReportStartDate = String(startInput.value || '');
    inventoryReportEndDate = String(endInput.value || '');
    renderStockReports();
}

