function printUsageModelsMasterDetailReport() {
    const models = (usageModels || [])
        .slice()
        .sort((a, b) => String(a && a.nome_modelo || '').localeCompare(String(b && b.nome_modelo || ''), 'pt-BR'))
        .map(m => {
            const items = getModelItemsByModelId(String(m && m.id || ''));
            const subtotalItens = items.length;
            const subtotalQtd = items.reduce((sum, mi) => sum + toDec(mi && mi.quantidade_sugerida, 1), 0);
            const includeBiosseg = !(m && m.include_biosseguranca === false);
            return { model: m, items, subtotalItens, subtotalQtd, includeBiosseg };
        });
    if (!models.length) {
        showToast('Nenhum modelo cadastrado para impressão.', true);
        return;
    }
    const totalGeralItens = models.reduce((sum, x) => sum + x.subtotalItens, 0);
    const totalGeralQtd = models.reduce((sum, x) => sum + x.subtotalQtd, 0);
    const masterRows = models.map(x => `
        <tr>
            <td>${String(x && x.model && x.model.nome_modelo || 'Modelo')}</td>
            <td class="num">${x.subtotalItens}</td>
            <td class="num">${x.subtotalQtd.toFixed(2)}</td>
            <td>${x.includeBiosseg ? 'Sim' : 'Não'}</td>
        </tr>
    `).join('');
    const detailModels = models;
    const detailBlocks = detailModels.map(x => `
        <div class="detail-card">
            <div class="detail-title">Itens do Modelo: ${String(x && x.model && x.model.nome_modelo || 'Modelo')}</div>
            <table class="report-table">
                <thead><tr><th>Material</th><th style="width:120px;">Unidade</th><th class="num" style="width:140px;">Qtd Sugerida</th></tr></thead>
                <tbody>
                    ${x.items.length ? x.items.map(mi => {
                        const inv = getInventoryById(mi && mi.inventory_id);
                        return `<tr><td>${getInventoryNameById(mi && mi.inventory_id)}</td><td>${String(inv && inv.unidade || '—')}</td><td class="num">${toDec(mi && mi.quantidade_sugerida, 1).toFixed(2)}</td></tr>`;
                    }).join('') : '<tr><td colspan="3">Modelo sem itens</td></tr>'}
                </tbody>
                <tfoot>
                    <tr class="total-row"><td colspan="2">Subtotal (itens)</td><td class="num">${x.subtotalItens}</td></tr>
                </tfoot>
            </table>
        </div>
    `).join('');
    const html = `
        <style>
            .report-table { width:100%; border-collapse:collapse; font-size: 12px; }
            .report-table th, .report-table td { border:1px solid #e2e8f0; padding:8px; vertical-align:top; }
            .report-table thead th { background:#f1f5f9; text-align:left; }
            .report-table .num { text-align:right; font-variant-numeric: tabular-nums; }
            .report-section-title { margin: 10px 0 8px 0; font-size: 14px; color:#0f172a; }
            .meta-table td { border:1px solid #e2e8f0; padding:8px; }
            .total-row td { font-weight: 800; border-top:2px solid #cbd5e1; background:#fff; }
            .detail-card { margin-top: 12px; padding: 10px; border:1px solid #e2e8f0; border-radius:10px; background:#fff; }
            .detail-title { font-weight: 900; margin: 0 0 8px 0; color:#0f172a; }
            hr { border:0; border-top:1px solid #e2e8f0; margin: 14px 0; }
            @media print {
                .detail-card { break-inside: avoid; page-break-inside: avoid; }
                .report-table thead { display: table-header-group; }
            }
        </style>
        <div class="report-section-title">MODELO (Master)</div>
        <table class="report-table">
            <thead><tr><th>Modelo</th><th class="num" style="width:140px;">Subtotal (itens)</th><th class="num" style="width:160px;">Subtotal (qtd sugerida)</th><th style="width:180px;">Biossegurança</th></tr></thead>
            <tbody>${masterRows}</tbody>
            <tfoot>
                <tr class="total-row"><td>Total Geral</td><td class="num">${totalGeralItens}</td><td class="num">${totalGeralQtd.toFixed(2)}</td><td class="num">${models.length} modelos</td></tr>
            </tfoot>
        </table>
        <hr>
        <div class="report-section-title">Detail (Itens do Kit)</div>
        ${detailBlocks}
    `;
    openStockReportPrintWindow('Relatório de Modelos de Uso (Master/Detail)', html);
}

function renderInventoryNameSuggestions(query = '') {
    const list = document.getElementById('inventoryNomeSuggestions');
    if (!list) return;
    const q = normalizeKey(normalizeInventoryName(query));
    const names = Array.from(new Set((inventoryItems || []).map(i => normalizeInventoryName(i && i.nome || '')).filter(Boolean)));
    const ordered = names
        .filter(n => !q || normalizeKey(n).includes(q))
        .sort((a, b) => {
            const aStarts = q && normalizeKey(a).startsWith(q) ? 0 : 1;
            const bStarts = q && normalizeKey(b).startsWith(q) ? 0 : 1;
            if (aStarts !== bStarts) return aStarts - bStarts;
            return a.localeCompare(b, 'pt-BR');
        })
        .slice(0, 12);
    list.innerHTML = ordered.map(n => `<option value="${n}"></option>`).join('');
}

function renderInventoryAreaFilterOptions() {
    const select = document.getElementById('inventoryAreaFilter');
    if (!select) return;
    const sourceRows = inventoryShowLibraryFull ? (inventoryItems || []).filter(i => !isInventoryActive(i)) : (inventoryItems || []).filter(isInventoryActive);
    const fallbackAreas = Array.from(new Set(sourceRows.map(getInventoryArea))).sort((a, b) => a.localeCompare(b, 'pt-BR'));
    const areas = (inventoryAreaOptions && inventoryAreaOptions.length) ? inventoryAreaOptions : fallbackAreas;
    select.innerHTML = `<option value="">Todas as Áreas</option>${areas.map(a => `<option value="${a}">${a}</option>`).join('')}`;
    if (inventoryAreaFilter && areas.includes(inventoryAreaFilter)) {
        select.value = inventoryAreaFilter;
    } else {
        inventoryAreaFilter = '';
        select.value = '';
    }
}

