// Función para atualizar campos do serviço selecionado
function updateBudgetItemFromService(serviceId) {
    if (!serviceId) {
        // Se deselecionar, limpa os campos
        document.getElementById('budItemDescricao').value = '';
        const subSelect = document.getElementById('budItemSubdivisao');
        if (subSelect) subSelect.value = '';
        document.getElementById('budItemValor').value = '';
        return false;
    }
    const serv = services.find(s => String(s && s.id || '') === String(serviceId || ''));
    if (serv) {
        document.getElementById('budItemDescricao').value = serv.descricao;

        const subSelect = document.getElementById('budItemSubdivisao');
        if (subSelect) {
            const raw = String(serv.subdivisao || '').trim();
            const rawSubId = String(serv.subdivisao_id || '').trim();
            if (!subSelect.options || subSelect.options.length <= 1) {
                populateBudgetItemSubdivisaoDropdown();
            }
            if (!raw) {
                subSelect.value = '-';
            } else {
                const rawTrim = raw;
                subSelect.value = rawTrim;
                if (subSelect.value !== rawTrim) {
                    const options = Array.from(subSelect.options);
                    const optById = rawSubId ? options.find(o => String(o && o.dataset && o.dataset.subid || '').trim() === rawSubId) : null;
                    const optExact = options.find(o => String(o.value || '').trim() === rawTrim);
                    if (optById) {
                        subSelect.value = optById.value;
                    } else if (optExact) {
                        subSelect.value = optExact.value;
                    } else {
                        const rawKey = normalizeKey(rawTrim);
                        const optByName = options.find(o => {
                            const v = String(o.value || '');
                            const tail = v.includes('-') ? v.split('-').slice(1).join('-') : v;
                            const n1 = normalizeKey(tail);
                            const n2 = normalizeKey(v);
                            const n3 = normalizeKey(String(o && o.dataset && o.dataset.subnome || ''));
                            return n1 === rawKey || n2 === rawKey || n3 === rawKey;
                        });
                        if (optByName) {
                            subSelect.value = optByName.value;
                        } else {
                            const optDyn = document.createElement('option');
                            optDyn.value = rawTrim;
                            optDyn.textContent = rawTrim;
                            optDyn.dataset.subid = rawSubId;
                            optDyn.dataset.subnome = rawTrim;
                            subSelect.appendChild(optDyn);
                            subSelect.value = rawTrim;
                        }
                    }
                }
            }
        }

        const valorEl = document.getElementById('budItemValor');
        valorEl.value = serv.valor || 0;
        valorEl.readOnly = true;
        valorEl.classList.add('readonly-input');

        // Feedback visual
        valorEl.style.backgroundColor = '#ecfdf5';
        setTimeout(() => {
            const el = document.getElementById('budItemValor');
            if (el) el.style.backgroundColor = '';
        }, 800);

        if (typeof validateBudgetItemForm === 'function') validateBudgetItemForm();
        syncBudgetItemCalcFromOdonto();
        return true;
    }
    return false;
}

function renderOdontoSelectionsMap() {
    if (!odontogramaSvg) return;
    odontogramaSvg.querySelectorAll('.tooth').forEach(g => {
        const t = g.getAttribute('data-tooth');
        if (odontoSelectionsMap.has(t)) {
            g.classList.add('selected');
        } else {
            g.classList.remove('selected');
        }
    });
}

function parseOdontoStringIntoMap(valStr) {
    odontoSelectionsMap.clear();
    const parts = String(valStr || '').split(',').map(s => s.trim()).filter(Boolean);
    
    // Suporta formato antigo "18,17" e formato novo "18 (V,M), 17"
    // Usamos vírgula para separar os dentes na raiz, então as faces dentro do parênteses não podem usar vírgula.
    // O ideal seria usar vírgula e ter um regex forte, mas vamos adotar ';' ou espaço para separar faces se precisar,
    // ou assumir que o sistema só usa "18 (V M)" ou "18 (V,M)" se ajustarmos o split.
    // Vamos fazer um regex robusto para extrair `Dente (Faces)` ignorando a vírgula como split primário.
}

// Melhor função de parse para lidar com "18 (V, M), 17"
function parseOdontoStringRobust(valStr) {
    odontoSelectionsMap.clear();
    const str = String(valStr || '').trim();
    if (!str) return;
    
    // Divide por vírgula, mas IGNORA vírgulas dentro de parênteses
    const parts = str.match(/(?:[^,(]|\([^)]*\))+/g);
    if (!parts) return;

    parts.forEach(p => {
        const item = p.trim();
        if (!item) return;
        
        const match = item.match(/^(\d+)(?:\s*\(([^)]+)\))?$/);
        if (match) {
            const tooth = match[1];
            // Se tiver faces, divide por vírgula, ponto e vírgula ou espaço e limpa
            const faces = match[2] ? match[2].split(/[,;\s]+/).map(f => f.trim()).filter(Boolean) : [];
            odontoSelectionsMap.set(tooth, faces);
        } else if (/^\d+$/.test(item)) {
            odontoSelectionsMap.set(item, []);
        }
    });
}

function serializeOdontoMapToString() {
    const arr = [];
    // Para manter a ordem de inserção do Map
    odontoSelectionsMap.forEach((faces, tooth) => {
        if (faces && faces.length > 0) {
            arr.push(`${tooth} (${faces.join(', ')})`);
        } else {
            arr.push(tooth);
        }
    });
    return arr.join(', ');
}

function openOdontoFacesModal(toothId) {
    currentEditingTooth = toothId;
    currentToothFaces.clear();
    
    if (odontoSelectionsMap.has(toothId)) {
        const savedFaces = odontoSelectionsMap.get(toothId) || [];
        savedFaces.forEach(f => currentToothFaces.add(f));
    }
    
    if (modalOdontoFacesTitle) {
        modalOdontoFacesTitle.textContent = `Faces do Dente ${toothId}`;
    }
    
    // Atualiza botões
    odontoFaceBtns.forEach(btn => {
        const face = btn.getAttribute('data-face');
        if (currentToothFaces.has(face)) {
            btn.classList.remove('btn-secondary');
            btn.classList.add('btn-primary');
        } else {
            btn.classList.remove('btn-primary');
            btn.classList.add('btn-secondary');
        }
    });
    
    if (btnCancelFaces) {
        btnCancelFaces.textContent = odontoSelectionsMap.has(toothId) ? 'Remover Dente' : 'Cancelar';
    }
    
    if (modalOdontoFaces) {
        modalOdontoFaces.classList.remove('hidden');
    }
}

function bindOdontoFacesModalEvents() {
    odontoFaceBtns.forEach(btn => {
        if (btn.__boundFaces) return;
        btn.__boundFaces = true;
        btn.addEventListener('click', (e) => {
            const face = btn.getAttribute('data-face');
            if (currentToothFaces.has(face)) {
                currentToothFaces.delete(face);
                btn.classList.remove('btn-primary');
                btn.classList.add('btn-secondary');
            } else {
                currentToothFaces.add(face);
                btn.classList.remove('btn-secondary');
                btn.classList.add('btn-primary');
            }
        });
    });
    
    if (btnCancelFaces && !btnCancelFaces.__bound) {
        btnCancelFaces.__bound = true;
        btnCancelFaces.addEventListener('click', () => {
            if (currentEditingTooth) {
                // Remove o dente inteiro da seleção
                odontoSelectionsMap.delete(currentEditingTooth);
                renderOdontoSelectionsMap();
            }
            if (modalOdontoFaces) modalOdontoFaces.classList.add('hidden');
            currentEditingTooth = null;
        });
    }
    
    if (btnConfirmFaces && !btnConfirmFaces.__bound) {
        btnConfirmFaces.__bound = true;
        btnConfirmFaces.addEventListener('click', () => {
            if (currentEditingTooth) {
                odontoSelectionsMap.set(currentEditingTooth, Array.from(currentToothFaces));
                renderOdontoSelectionsMap();
            }
            if (modalOdontoFaces) modalOdontoFaces.classList.add('hidden');
            currentEditingTooth = null;
        });
    }
}

function bindOdontogramaEvents() {
    if (btnOpenOdontograma && !btnOpenOdontograma.__bound) {
        btnOpenOdontograma.__bound = true;
        btnOpenOdontograma.addEventListener('click', () => {
            const svc = getSelectedBudgetService();
            const canSelect = serviceRequiresOdonto(svc);
            if (!canSelect) {
                showToast('Este serviço não exige seleção por elemento.', true);
                return;
            }
            if (modalOdontograma) modalOdontograma.classList.remove('hidden');
            window.__odontoDraftStartVal = String(budItemOdontoTeeth && budItemOdontoTeeth.value || '');
            parseOdontoStringRobust(window.__odontoDraftStartVal);
            renderOdontoSelectionsMap();
            syncBudgetItemCalcFromOdonto();
        });
    }
    if (btnCloseModalOdonto && !btnCloseModalOdonto.__bound) {
        btnCloseModalOdonto.__bound = true;
        btnCloseModalOdonto.addEventListener('click', () => {
            parseOdontoStringRobust(window.__odontoDraftStartVal);
            renderOdontoSelectionsMap();
            if (modalOdontograma) modalOdontograma.classList.add('hidden');
        });
    }
    if (btnCancelOdonto && !btnCancelOdonto.__bound) {
        btnCancelOdonto.__bound = true;
        btnCancelOdonto.addEventListener('click', () => {
            parseOdontoStringRobust(window.__odontoDraftStartVal);
            renderOdontoSelectionsMap();
            if (modalOdontograma) modalOdontograma.classList.add('hidden');
        });
    }
    if (odontogramaSvg && !odontogramaSvg.__bound) {
        odontogramaSvg.__bound = true;
        odontogramaSvg.addEventListener('click', (e) => {
            const tooth = e && e.target && typeof e.target.closest === 'function'
                ? e.target.closest('.tooth')
                : null;
            if (!tooth) return;
            const t = tooth.getAttribute('data-tooth');
            if (!t) return;
            
            // Abre o modal de faces (adiciona o dente se já não estiver no Map)
            if (!odontoSelectionsMap.has(t)) {
                odontoSelectionsMap.set(t, []);
            }
            renderOdontoSelectionsMap();
            openOdontoFacesModal(t);
        });
    }
    if (btnConfirmOdonto && !btnConfirmOdonto.__bound) {
        btnConfirmOdonto.__bound = true;
        btnConfirmOdonto.addEventListener('click', () => {
            const val = serializeOdontoMapToString();
            if (budItemOdontoTeeth) budItemOdontoTeeth.value = val;
            if (budItemOdontoDisplay) {
                const elsMatch = val ? val.match(/(?:[^,(]|\([^)]*\))+/g) : [];
                const list = elsMatch ? elsMatch.map(x => String(x).trim()) : [];
                budItemOdontoDisplay.value = list.length ? list.join(' • ') : 'Nenhum dente selecionado';
            }
            window.__odontoDraftStartVal = '';
            syncBudgetItemCalcFromOdonto();
            if (modalOdontograma) modalOdontograma.classList.add('hidden');
        });
    }
    
    bindOdontoFacesModalEvents();
}

