window.printServiceList = function (subFilter = '', orientation = 'landscape', fontSize = 'medium') {
    const subToken = String(subFilter || '').trim().toUpperCase();
    const filteredBase = Array.isArray(services) ? services : [];
    const filtered = !subToken
        ? filteredBase
        : filteredBase.filter(s => String(s && s.subdivisao || '').trim().toUpperCase() === subToken);
    const hoje = new Date().toLocaleDateString('pt-BR', { day: '2-digit', month: 'long', year: 'numeric' });
    const pageOrientation = String(orientation || '').toLowerCase() === 'portrait' ? 'portrait' : 'landscape';
    const fontMode = String(fontSize || 'medium').toLowerCase();
    const fontCfg = fontMode === 'large'
        ? { th: 11, td: 11, row: 22, occ: 20, sub: 13, desc: 12, title: 16, date: 11, footer: 11 }
        : fontMode === 'small'
            ? { th: 8, td: 8, row: 16, occ: 14, sub: 10, desc: 9, title: 12, date: 9, footer: 9 }
            : { th: 9, td: 9, row: 18, occ: 18, sub: 12, desc: 11, title: 14, date: 10, footer: 10 };
    const portraitCfg = {
        th: Math.max(7, Math.round(fontCfg.th * 0.82)),
        td: Math.max(7, Math.round(fontCfg.td * 0.82)),
        row: Math.max(10, Math.round(fontCfg.row * 0.62)),
        occ: Math.max(12, Math.round(fontCfg.occ * 0.78)),
        sub: Math.max(8, Math.round(fontCfg.sub * 0.75)),
        desc: Math.max(8, Math.round(fontCfg.desc * 0.75)),
        title: Math.max(10, Math.round(fontCfg.title * 0.78)),
        date: Math.max(8, Math.round(fontCfg.date * 0.78)),
        footer: Math.max(8, Math.round(fontCfg.footer * 0.9))
    };
    const rowsPerPage = pageOrientation === 'portrait' ? 65 : 27;
    const col = pageOrientation === 'portrait'
        ? { id: 36, desc: 170, tipo: 44, sub: 98, calc: 62, odo: 50, val: 58 }
        : { id: 60, desc: 330, tipo: 90, sub: 190, calc: 140, odo: 120, val: 120 };
    const pages = [];
    for (let i = 0; i < filtered.length; i += rowsPerPage) pages.push(filtered.slice(i, i + rowsPerPage));
    if (!pages.length) pages.push([]);

    const pageHtml = pages.map((chunk, pageIndex) => {
        const bodyRows = chunk.map((s) => {
            const tipoCalculo = String(s && s.tipo_calculo || 'Fixo');
            const odontograma = (s && s.exige_elemento) ? 'SIM' : 'NÃO';
            let sub = s.subdivisao ? s.subdivisao.replace(/^\d+\.\d+\s*-\s*/, '').trim() : '-';
            return `
                <tr>
                    <td>${s.seqid || ''}</td>
                    <td>${escapeHtml(String(s.descricao || ''))}</td>
                    <td>${s.ie === 'S' ? 'Serviço' : 'Estoque'}</td>
                    <td>${escapeHtml(sub)}</td>
                    <td>${escapeHtml(tipoCalculo)}</td>
                    <td>${odontograma}</td>
                    <td style="text-align: right;">R$ ${Number(s.valor || 0).toFixed(2)}</td>
                </tr>
            `;
        }).join('');

        const colgroup = `
            <colgroup>
                <col style="width:${col.id}px;">
                <col style="width:${col.desc}px;">
                <col style="width:${col.tipo}px;">
                <col style="width:${col.sub}px;">
                <col style="width:${col.calc}px;">
                <col style="width:${col.odo}px;">
                <col style="width:${col.val}px;">
            </colgroup>
        `;
        const tableHead = pageIndex === 0 ? `
            <thead>
                <tr>
                    <th>ID</th>
                    <th>DESCRIÇÃO</th>
                    <th>TIPO</th>
                    <th>SUBDIVISÃO</th>
                    <th>TIPO CÁLCULO</th>
                    <th>ODONTOGRAMA</th>
                    <th style="text-align: right;">VALOR</th>
                </tr>
            </thead>
        ` : '';

        const footerText = pageIndex === pages.length - 1
            ? `Quantidade total de itens: ${filtered.length} • Página ${pageIndex + 1} de ${pages.length}`
            : `Página ${pageIndex + 1} de ${pages.length}`;

        return `
            <section class="catalog-page ${pageOrientation}${pageIndex < pages.length - 1 ? ' break-after' : ''}">
                <div class="catalog-title-wrap">
                    <div class="catalog-title-left">
                        <div class="catalog-occ">OCC</div>
                        <div class="catalog-sub">Odonto Connect Cloud</div>
                        <div class="catalog-desc">Relatório de Serviços e Itens de Estoque</div>
                    </div>
                    <div class="catalog-title-right">
                        <div class="catalog-title">CATÁLOGO GERAL</div>
                        <div class="catalog-date">Emitido em: ${hoje}</div>
                    </div>
                </div>
                <table class="catalogo-servicos">
                    ${colgroup}
                    ${tableHead}
                    <tbody>
                        ${bodyRows || '<tr><td colspan="7" style="text-align:center">Nenhum item encontrado.</td></tr>'}
                    </tbody>
                </table>
                <div class="catalog-footer">${footerText}</div>
            </section>
        `;
    }).join('');

    const html = `
        <!DOCTYPE html>
        <html lang="pt-BR">
        <head>
            <meta charset="UTF-8">
            <title>Catálogo de Serviços</title>
            <style>
                * { margin:0; padding:0; box-sizing:border-box; }
                body { font-family: Arial, sans-serif; font-size: 11px; color:#1f2937; padding: 10mm; direction:ltr; }
                .catalog-page { width: 100%; }
                .catalog-page.break-after { page-break-after: always; break-after: page; }
                .catalog-title-wrap { display:flex; justify-content:space-between; align-items:flex-start; border-bottom:2px solid #0066cc; padding-bottom:8px; margin-bottom:10px; }
                .catalog-occ { font-size:${fontCfg.occ}px; font-weight:800; color:#0066cc; line-height:1; }
                .catalog-sub { font-size:${fontCfg.sub}px; font-weight:600; color:#6b7280; margin-top:2px; }
                .catalog-desc { font-size:${fontCfg.desc}px; color:#6b7280; margin-top:2px; }
                .catalog-title { font-size:${fontCfg.title}px; font-weight:800; text-align:right; color:#374151; }
                .catalog-date { color:#6b7280; font-size:${fontCfg.date}px; margin-top:2px; text-align:right; }
                table.catalogo-servicos { width:100%; border-collapse:collapse; margin-top:4px; table-layout: fixed; }
                .catalogo-servicos th, .catalogo-servicos td {
                    border:1px solid #e5e7eb;
                    padding:3px 4px;
                    text-align:left;
                    vertical-align:middle;
                    line-height:1.1;
                    white-space:nowrap;
                    overflow:hidden;
                    text-overflow:ellipsis;
                }
                .catalogo-servicos th { background:#f3f4f6; color:#374151; font-weight:700; text-transform:uppercase; font-size:${fontCfg.th}px; }
                .catalogo-servicos td { font-size:${fontCfg.td}px; }
                .catalogo-servicos tbody tr { height:${fontCfg.row}px; }
                .catalog-footer { margin-top:8px; border-top:1px solid #e5e7eb; padding-top:6px; font-size:${fontCfg.footer}px; color:#6b7280; text-align:right; font-weight:700; }
                .catalog-page.portrait .catalog-title-wrap { margin-bottom:6px; }
                .catalog-page.portrait .catalog-occ { font-size:${portraitCfg.occ}px; }
                .catalog-page.portrait .catalog-sub { font-size:${portraitCfg.sub}px; }
                .catalog-page.portrait .catalog-desc { font-size:${portraitCfg.desc}px; }
                .catalog-page.portrait .catalog-title { font-size:${portraitCfg.title}px; }
                .catalog-page.portrait .catalog-date { font-size:${portraitCfg.date}px; }
                .catalog-page.portrait .catalogo-servicos th,
                .catalog-page.portrait .catalogo-servicos td { padding:2px 2px; line-height:1.0; }
                .catalog-page.portrait .catalogo-servicos th { font-size:${portraitCfg.th}px; }
                .catalog-page.portrait .catalogo-servicos td { font-size:${portraitCfg.td}px; }
                .catalog-page.portrait .catalogo-servicos tbody tr { height:${portraitCfg.row}px; }
                @media print { @page { size: A4 ${pageOrientation}; margin: 6mm; } }
            </style>
        </head>
        <body>${pageHtml}</body>
        </html>
    `;

    const w = window.open('', '_blank', 'width=1000,height=700');
    if (!w) { showToast('Habilite pop-ups para imprimir.', true); return; }
    w.document.write(html);
    w.document.close();
    w.focus();
    setTimeout(() => w.print(), 350);
};

window.printSpecialtiesMasterDetail = function () {
    const hoje = new Date().toLocaleDateString('pt-BR', { day: '2-digit', month: 'long', year: 'numeric' });
    const list = Array.isArray(specialties) ? [...specialties].sort((a, b) => Number(a.seqid || 0) - Number(b.seqid || 0)) : [];
    let totalGeral = 0;
    let bodyHtml = '';

    list.forEach(spec => {
        const subs = Array.isArray(spec && spec.subdivisoes) ? spec.subdivisoes : [];
        totalGeral += subs.length;
        const rows = subs.map((sub, i) => `
            <tr>
                <td style="width:90px;">${spec.seqid}.${i + 1}</td>
                <td>${String(sub && sub.nome || '-')}</td>
            </tr>
        `).join('');
        bodyHtml += `
            <div style="margin-top: 14px; border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">
                <div style="background:#f3f4f6; padding:8px 10px; font-weight:700; color:#111827;">
                    ${spec.seqid} - ${spec.nome}
                </div>
                <table style="width:100%; border-collapse: collapse;">
                    <thead>
                        <tr>
                            <th style="text-align:left; border-bottom:1px solid #e5e7eb; padding:6px 10px; width:90px;">CÓD.</th>
                            <th style="text-align:left; border-bottom:1px solid #e5e7eb; padding:6px 10px;">SUBDIVISÃO</th>
                        </tr>
                    </thead>
                    <tbody>
                        ${rows || '<tr><td colspan="2" style="padding:8px 10px; color:#6b7280;">Nenhuma subdivisão cadastrada.</td></tr>'}
                    </tbody>
                </table>
                <div style="padding:8px 10px; border-top:1px solid #e5e7eb; text-align:right; font-weight:700;">
                    Subtotal de itens: ${subs.length}
                </div>
            </div>
        `;
    });

    const html = `
        <!DOCTYPE html>
        <html lang="pt-BR">
            <head>
                <meta charset="UTF-8">
                <title>Relatório Master/Detail - Especialidades</title>
                <style>
                    * { box-sizing: border-box; }
                    body { font-family: Arial, sans-serif; font-size: 12px; color:#1f2937; padding: 18px; }
                    .header { display:flex; justify-content:space-between; align-items:flex-start; border-bottom:2px solid #0066cc; padding-bottom:10px; margin-bottom:12px; }
                    .title { font-size:16px; font-weight:700; color:#0066cc; }
                    .subtitle { font-size:12px; color:#6b7280; margin-top:2px; }
                    .footer { margin-top: 16px; border-top:1px solid #e5e7eb; padding-top:8px; font-weight:700; text-align:right; }
                </style>
            </head>
            <body>
                <div class="header">
                    <div>
                        <div class="title">OCC - Relatório Master/Detail</div>
                        <div class="subtitle">Especialidades e Subdivisões</div>
                    </div>
                    <div class="subtitle">Emitido em: ${hoje}</div>
                </div>
                ${bodyHtml || '<div style="color:#6b7280;">Nenhuma especialidade cadastrada.</div>'}
                <div class="footer">Total geral de itens: ${totalGeral}</div>
            </body>
        </html>`;

    const ok = openOCCReportPrintWindowFromLegacyHtml({ reportName: 'Especialidades (Master/Detail)', legacyHtml: html, width: 1000, height: 700 });
    if (!ok) return;
};

